/**
 * @summary List fraud events (teacher/admin only)
 */
export const getListFraudEventsUrl = (params?: ListFraudEventsParams,) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {

    if (value !== undefined) {
      normalizedParams.append(key, value === null ? 'null' : value.toString())
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0 ? `/api/fraud/events?${stringifiedParams}` : `/api/fraud/events`
}

