/**
 * @summary List published courses (public, no auth required)
 */
export const getListPublicCoursesUrl = (params?: ListPublicCoursesParams,) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {

    if (value !== undefined) {
      normalizedParams.append(key, value === null ? 'null' : value.toString())
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0 ? `/api/catalog/courses?${stringifiedParams}` : `/api/catalog/courses`
}

